<?php

$path = __DIR__.'/../resources/views/comercio/dashboard.blade.php';
$content = file_get_contents($path);

if ($content === false) {
    fwrite(STDERR, "ERROR: No se pudo leer dashboard.blade.php\n");
    exit(1);
}

$marker = 'data-commerce-tab-panel="branding"';
$markerPosition = strpos($content, $marker);

if ($markerPosition === false) {
    fwrite(STDERR, "ERROR: No se encontro el panel Branding.\n");
    exit(1);
}

$panelStart = strrpos(substr($content, 0, $markerPosition), '<div');

if ($panelStart === false) {
    fwrite(STDERR, "ERROR: No se encontro el inicio del panel Branding.\n");
    exit(1);
}

$endSectionPosition = strpos($content, '@endsection', $markerPosition);

if ($endSectionPosition === false) {
    fwrite(STDERR, "ERROR: No se encontro @endsection despues del panel Branding.\n");
    exit(1);
}

$sectionClosePosition = strrpos(substr($content, 0, $endSectionPosition), '</section>');

if ($sectionClosePosition === false || $sectionClosePosition <= $panelStart) {
    fwrite(STDERR, "ERROR: No se encontro el cierre principal del dashboard.\n");
    exit(1);
}

$panel = base64_decode('', true);

if ($panel === false) {
    fwrite(STDERR, "ERROR: No se pudo decodificar el panel Branding.\n");
    exit(1);
}

$content = substr($content, 0, $panelStart)
    .$panel."\n"
    .substr($content, $sectionClosePosition);

$content = preg_replace(
    '~comercio-branding\.css\'\) \}\}\?v=[^"\']+~',
    "comercio-branding.css') }}?v=20260711-04",
    $content,
    1
);

$content = preg_replace(
    '~comercio-branding\.js\'\) \}\}\?v=[^"\']+~',
    "comercio-branding.js') }}?v=20260711-04",
    $content,
    1
);

if (file_put_contents($path, $content) === false) {
    fwrite(STDERR, "ERROR: No se pudo guardar dashboard.blade.php\n");
    exit(1);
}

echo "OK: Panel Branding reemplazado con asignacion por sucursal.\n";